func isKnownActionName(name string) bool {
	if name == "" {
		return false
	}
	if GetAction(name) != nil {
		return true
	}
	return builtinActionNames[name]
}

func isKnownConditionName(name string) bool {
	if name == "" {
		return false
	}
	if GetCondition(name) != nil {
		return true
	}
	return builtinConditionNames[name]
}
